content.content:
  1→import { Button } from "@/components/ui/button";
  2→import { Input } from "@/components/ui/input";
  3→import { Badge } from "@/components/ui/badge";
  4→import { PlatformIcon } from "@/components/PlatformIcon";
  5→import {
  6→  Dialog,
  7→  DialogContent,
  8→  DialogHeader,
  9→  DialogTitle,
 10→  DialogDescription,
 11→  DialogBody,
 12→  DialogFooter,
 13→} from "@/components/ui/dialog";
 14→import {
 15→  CheckFill,
 16→  User3Fill,
 17→  AiFill,
 18→  AddLine,
 19→  Edit2Line,
 20→  Delete2Line,
 21→  SearchLine,
 22→  CloseLine,
 23→} from "@mingcute/react";
 24→import { cn } from "@/lib/utils";
 25→import type { ClawHubSkill } from "@/hooks/useSkillSearch";
 26→
 27→type ActionDef = {
 28→  type: string;
 29→  label: string;
 30→  fields:
 31→    | "follow"
 32→    | "post_url"
 33→    | "post_content"
 34→    | "quote_post"
 35→    | "discord_join"
 36→    | "discord_role"
 37→    | "telegram_join";
 38→};
 39→
 40→const PLATFORM_ICON_KEYS: Record<string, "x" | "discord" | "telegram"> = {
 41→  X: "x",
 42→  Discord: "discord",
 43→  Telegram: "telegram",
 44→};
 45→
 46→function PlatformBtnIcon({ platform }: { platform: string }) {
 47→  const key = PLATFORM_ICON_KEYS[platform];
 48→  if (!key) return <span>{platform[0]}</span>;
 49→  return <PlatformIcon name={key} size={16} colored />;
 50→}
 51→
 52→// Set to null to show all task types; use Set(["like_post", "repost", "post"]) to hide until backend verification
 53→const HIDDEN_ACTION_TYPES: Set<string> | null = null;
 54→
 55→const PLATFORM_ACTIONS: Record<string, ActionDef[]> = {
 56→  X: [
 57→    { type: "follow_account", label: "Follow on X", fields: "follow" },
 58→    { type: "like_post", label: "Like a Post", fields: "post_url" },
 59→    { type: "repost", label: "Repost a Post", fields: "post_url" },
 60→    { type: "post", label: "Post on X", fields: "post_content" },
 61→    { type: "quote_post", label: "Quote a Post", fields: "quote_post" },
 62→  ],
 63→  Discord: [
 64→    {
 65→      type: "join_server",
 66→      label: "Join a Discord Server",
 67→      fields: "discord_join",
 68→    },
 69→    {
 70→      type: "verify_role",
 71→      label: "Verify Role in Discord",
 72→      fields: "discord_role",
 73→    },
 74→  ],
 75→  Telegram: [
 76→    {
 77→      type: "join_channel",
 78→      label: "Join a Group or Channel",
 79→      fields: "telegram_join",
 80→    },
 81→  ],
 82→};
 83→
 84→interface SocialEntry {
 85→  platform: string;
 86→  action: string;
 87→  actionType: string;
 88→  icon: string;
 89→  params: Record<string, string>;
 90→  chips: string[];
 91→  requireTagFriends?: boolean;
 92→}
 93→
 94→type Skill =
 95→  | Pick<ClawHubSkill, "id" | "name" | "desc" | "agents" | "version">
 96→  | ClawHubSkill;
 97→
 98→interface TaskValidationError {
 99→  index: number;
100→  field: string;
101→  message: string;
102→}
103→
104→type ChipStatus = "pending" | "valid" | "invalid";
105→
106→interface StepTasksProps {
107→  isActive: boolean;
108→  isDone: boolean;
109→  isValid: boolean;
110→  isFuture: boolean;
111→  stepSummary?: string;
112→  activePlatform: string | null;
113→  expandedTask: number | null;
114→  humanTasks: SocialEntry[];
115→  requiredSkills: Skill[];
116→  requireVerified: boolean;
117→  skillSearch: string;
118→  skillSearchResults: ClawHubSkill[];
119→  skillSearchLoading: boolean;
120→  showSkillResults: boolean;
121→  urlFetching: boolean;
122→  urlPreview: ClawHubSkill | null;
123→  urlFetchError: string | null;
124→  taskErrors: TaskValidationError[];
125→  addedSkillIds: Set<string>;
126→  expandedDescs: Set<string>;
127→  onToggle: () => void;
128→  onSetActivePlatform: (platform: string | null) => void;
129→  onAddHumanTask: (platform: string, action: ActionDef) => void;
130→  onRemoveHumanTask: (index: number) => void;
131→  onSetExpandedTask: (index: number | null) => void;
132→  onSetTaskParam: (index: number, key: string, value: string) => void;
133→  onToggleTagFriends: (index: number) => void;
134→  onAddChip: (index: number, value: string) => void;
135→  onRemoveChip: (index: number, chipIndex: number) => void;
136→  onSetRequireVerified: (value: boolean) => void;
137→  onSetSkillSearch: (value: string) => void;
138→  onSetShowSkillResults: (show: boolean) => void;
139→  onAddSkill: (skill: ClawHubSkill) => void;
140→  onRemoveSkill: (id: string) => void;
141→  onSetUrlFetching: (fetching: boolean) => void;
142→  onSetUrlPreview: (preview: ClawHubSkill | null) => void;
143→  onSetUrlFetchError: (error: string | null) => void;
144→  onToggleDesc: (id: string) => void;
145→  onTruncateDesc: (text: string, id: string) => React.ReactNode;
146→  onChipStatus: (
147→    platform: string,
148→    actionType: string,
149→    value: string,
150→  ) => ChipStatus | undefined;
151→  onPrevious: () => void;
152→  tasksNextAttempted: boolean;
153→  onTasksNext: () => void;
154→  SocialEntryBody: React.ComponentType<{
155→    task: SocialEntry;
156→    idx: number;
157→    setTaskParam: (i: number, key: string, val: string) => void;
158→    toggleTagFriends: (i: number) => void;
159→    addChip: (i: number, value: string) => void;
160→    removeChip: (i: number, chipIdx: number) => void;
161→    errors?: TaskValidationError[];
162→    chipStatus?: (value: string) => ChipStatus | undefined;
163→  }>;
164→  isSkillUrl: (url: string) => boolean;
165→  fetchSkillFromUrl: (url: string) => Promise<ClawHubSkill | null>;
166→}
167→
168→export function StepTasks({
169→  isActive,
170→  isDone,
171→  isValid,
172→  isFuture,
173→  stepSummary,
174→  activePlatform,
175→  expandedTask,
176→  humanTasks,
177→  requiredSkills,
178→  requireVerified,
179→  skillSearch,
180→  skillSearchResults,
181→  skillSearchLoading,
182→  showSkillResults,
183→  urlFetching,
184→  urlPreview,
185→  urlFetchError,
186→  taskErrors,
187→  addedSkillIds,
188→  onToggle,
189→  onSetActivePlatform,
190→  onAddHumanTask,
191→  onRemoveHumanTask,
192→  onSetExpandedTask,
193→  onSetTaskParam,
194→  onToggleTagFriends,
195→  onAddChip,
196→  onRemoveChip,
197→  onSetRequireVerified,
198→  onSetSkillSearch,
199→  onSetShowSkillResults,
200→  onAddSkill,
201→  onRemoveSkill,
202→  onSetUrlFetching,
203→  onSetUrlPreview,
204→  onSetUrlFetchError,
205→  onTruncateDesc,
206→  onChipStatus,
207→  onPrevious,
208→  tasksNextAttempted,
209→  onTasksNext,
210→  SocialEntryBody,
211→  isSkillUrl,
212→  fetchSkillFromUrl,
213→}: StepTasksProps) {
214→  return (
215→    <div
216→      className={cn(
217→        "relative mb-0 border-none rounded-none",
218→        "before:content-[''] before:absolute before:left-[13px] before:top-0 before:bottom-0 before:w-0.5 before:bg-border before:z-0",
219→        isDone && "before:bg-success",
220→      )}
221→    >
222→      <div
223→        className="flex items-start gap-3 py-4 cursor-pointer select-none text-xs relative z-1 group"
224→        onClick={onToggle}
225→      >
226→        <span
227→          className={cn(
228→            "relative z-10 size-7 rounded-full shrink-0 flex items-center justify-center text-xs font-semibold text-white border-2 border-background",
229→            isDone
230→              ? "bg-success shadow-[0_0_0_2px_var(--color-green-500)]"
231→              : isActive
232→                ? "bg-primary shadow-[0_0_0_2px_var(--primary)]"
233→                : "bg-gray-300 shadow-[0_0_0_2px_var(--color-gray-300)]",
234→          )}
235→        >
236→          {isDone ? <CheckFill size={12} /> : "2"}
237→        </span>
238→        <div className="flex-1 min-w-0">
239→          <div className="flex items-center gap-2">
240→            <span className="font-semibold text-sm text-fg-1 group-hover:text-primary">
241→              Tasks
242→            </span>
243→          </div>
244→          <div className="text-xs text-fg-3 mt-0.5 leading-snug truncate">
245→            {!isActive && stepSummary && stepSummary !== "No tasks"
246→              ? stepSummary
247→              : "Human social actions and agent skill requirements"}
248→          </div>
249→        </div>
250→        <div className="flex flex-col items-end gap-0.5 shrink-0 pt-0.5">
251→          <span className="text-xs text-fg-3 whitespace-nowrap">
252→            Step 2 of 4
253→          </span>
254→          <span
255→            className={cn(
256→              "text-xs whitespace-nowrap",
257→              isFuture ? "text-fg-3" : "text-primary",
258→            )}
259→          >
260→            {isDone ? "Modify if required" : isActive ? "" : "Add tasks"}
261→          </span>
262→        </div>
263→      </div>
264→      {isActive && (
265→        <div className="pl-10 pb-4">
266→          <div className="p-4 sm:p-6 border border-border-2 rounded bg-bg-1">
267→            <div className="space-y-4 mb-6">
268→              <div className="text-sm text-fg-1 mb-3.5 leading-snug">
269→                Define what needs to be done. Human tasks are social actions.
270→                Agent tasks require specific skills from{" "}
271→                <a
272→                  href="https://clawhub.ai/skills"
273→                  target="_blank"
274→                  rel="noreferrer"
275→                  className="text-primary underline"
276→                >
277→                  ClawHub
278→                </a>
279→                .
280→              </div>
281→              {tasksNextAttempted &&
282→                humanTasks.length === 0 &&
283→                requiredSkills.length === 0 && (
284→                  <div className="px-3 py-3 bg-warning-light border border-warning rounded text-xs text-fg-1 mb-4">
285→                    <strong>At least one task is required:</strong> add a human
286→                    (social) task or an agent skill from ClawHub.
287→                  </div>
288→                )}
289→
290→              {/* ── Human Tasks ── */}
291→              <div className="mb-6 border border-border-2 rounded-lg overflow-hidden">
292→                <div className="flex items-center gap-2 text-sm font-semibold px-4 py-3 border-b border-border-2 bg-bg-2">
293→                  <User3Fill size={16} className="text-(--human-fg)" /> Human
294→                  Tasks
295→                  <Badge variant="outline-primary" size="sm">
296→                    Social
297→                  </Badge>
298→                  <span className="font-normal text-xs text-fg-3 ml-auto">
299→                    Actions performed by the operator
300→                  </span>
301→                </div>
302→                <div className="p-0">
303→                  {humanTasks.length > 0 && (
304→                    <div className="p-4 border-b border-border-2">
305→                      {humanTasks.map((task, i) => (
306→                        <div
307→                          key={i}
308→                          className="border border-border-2 rounded mb-2 last:mb-0"
309→                          data-platform={task.platform.toLowerCase()}
310→                        >
311→                          <div className="flex items-start gap-2 px-3 py-2 bg-bg-2/50 text-sm select-none">
312→                            <span className="text-sm shrink-0 mt-0.5">
313→                              <PlatformBtnIcon platform={task.platform} />
314→                            </span>
315→                            <div className="flex-1 min-w-0">
316→                              <span className="font-semibold text-fg-1 truncate block">
317→                                {task.action}
318→                              </span>
319→                              {task.chips.length > 0 ||
320→                              task.params["content"] ? (
321→                                <span className="text-xs text-fg-3 truncate block mt-0.5">
322→                                  {task.chips.length > 0
323→                                    ? task.chips
324→                                        .slice(0, 3)
325→                                        .map((c) =>
326→                                          task.actionType === "follow_account"
327→                                            ? `@${c.replace(/^@/, "")}`
328→                                            : c,
329→                                        )
330→                                        .join(", ") +
331→                                      (task.chips.length > 3
332→                                        ? ` +${task.chips.length - 3}`
333→                                        : "")
334→                                    : task.params["content"]!.slice(0, 50) +
335→                                      (task.params["content"]!.length > 50
336→                                        ? "…"
337→                                        : "")}
338→                                </span>
339→                              ) : (
340→                                <span className="text-xs text-warning truncate block mt-0.5">
341→                                  Not configured — click edit
342→                                </span>
343→                              )}
344→                            </div>
345→                            <Button
346→                              variant="outline"
347→                              size="sm"
348→                              iconOnly
349→                              onClick={() =>
350→                                onSetExpandedTask(expandedTask === i ? null : i)
351→                              }
352→                            >
353→                              <Edit2Line size={14} />
354→                            </Button>
355→                            <Button
356→                              variant="outline"
357→                              size="sm"
358→                              iconOnly
359→                              onClick={() => onRemoveHumanTask(i)}
360→                            >
361→                              <Delete2Line size={14} />
362→                            </Button>
363→                          </div>
364→                          <Dialog
365→                            open={expandedTask === i}
366→                            onOpenChange={(open) => {
367→                              if (
368→                                !open &&
369→                                task.chips.length === 0 &&
370→                                !task.params["content"]
371→                              ) {
372→                                onRemoveHumanTask(i);
373→                              }
374→                              onSetExpandedTask(open ? i : null);
375→                            }}
376→                          >
377→                            <DialogContent>
378→                              <DialogHeader align="left">
379→                                <DialogTitle className="flex items-center gap-2">
380→                                  <PlatformBtnIcon platform={task.platform} />
381→                                  {task.action}
382→                                </DialogTitle>
383→                                <DialogDescription>
384→                                  Configure the details for this {task.platform}{" "}
385→                                  task.
386→                                </DialogDescription>
387→                              </DialogHeader>
388→                              <DialogBody>
389→                                <SocialEntryBody
390→                                  task={task}
391→                                  idx={i}
392→                                  setTaskParam={onSetTaskParam}
393→                                  toggleTagFriends={onToggleTagFriends}
394→                                  addChip={onAddChip}
395→                                  removeChip={onRemoveChip}
396→                                  errors={taskErrors}
397→                                  chipStatus={(v) =>
398→                                    onChipStatus(
399→                                      task.platform.toLowerCase(),
400→                                      task.actionType,
401→                                      v,
402→                                    )
403→                                  }
404→                                />
405→                              </DialogBody>
406→                              <DialogFooter className="flex! justify-end gap-2 space-x-0!">
407→                                <Button
408→                                  variant="outline"
409→                                  size="lg"
410→                                  onClick={() => {
411→                                    // Remove task if no data was entered
412→                                    if (
413→                                      task.chips.length === 0 &&
414→                                      !task.params["content"]
415→                                    ) {
416→                                      onRemoveHumanTask(i);
417→                                    }
418→                                    onSetExpandedTask(null);
419→                                  }}
420→                                >
421→                                  Cancel
422→                                </Button>
423→                                <Button
424→                                  size="lg"
425→                                  onClick={() => onSetExpandedTask(null)}
426→                                >
427→                                  {task.chips.length > 0 ||
428→                                  task.params["content"]
429→                                    ? "Save"
430→                                    : "Add Task"}
431→                                </Button>
432→                              </DialogFooter>
433→                            </DialogContent>
434→                          </Dialog>
435→                        </div>
436→                      ))}
437→                    </div>
438→                  )}
439→
440→                  {/* Tab picker for adding new tasks */}
441→                  <div className="p-4">
442→                    <div className="flex border-b border-border-2 mb-3 gap-6">
443→                      {Object.keys(PLATFORM_ACTIONS).map((p) => (
444→                        <button
445→                          key={p}
446→                          className={cn(
447→                            "flex items-center gap-2 py-2 text-sm font-medium cursor-pointer transition-colors border-b-3 -mb-px",
448→                            activePlatform === p
449→                              ? "border-fg-1 text-fg-1"
450→                              : "border-transparent text-fg-3 hover:text-fg-1 hover:border-border",
451→                          )}
452→                          onClick={() => onSetActivePlatform(p)}
453→                        >
454→                          <PlatformIcon
455→                            name={PLATFORM_ICON_KEYS[p] ?? "x"}
456→                            size={16}
457→                            colored
458→                          />
459→                          {p}
460→                        </button>
461→                      ))}
462→                    </div>
463→                    {activePlatform && (
464→                      <div className="flex flex-col gap-2">
465→                        {PLATFORM_ACTIONS[activePlatform]
466→                          .filter((a) => !HIDDEN_ACTION_TYPES?.has(a.type))
467→                          .map((action) => (
468→                            <div
469→                              key={action.type}
470→                              className="group/row flex items-center justify-between px-3 py-2 bg-bg-2/50 rounded border border-border-2 text-sm cursor-pointer transition-colors hover:bg-bg-2"
471→                              onClick={() =>
472→                                onAddHumanTask(activePlatform, action)
473→                              }
474→                            >
475→                              <span className="font-medium text-fg-1">
476→                                {action.label}
477→                              </span>
478→                              <Button
479→                                variant="default-tonal"
480→                                size="sm"
481→                                className="group-hover/row:bg-primary! group-hover/row:text-primary-foreground! transition-colors"
482→                              >
483→                                <AddLine size={14} />
484→                                Add
485→                              </Button>
486→                            </div>
487→                          ))}
488→                      </div>
489→                    )}
490→                  </div>
491→                </div>
492→              </div>
493→
494→              {/* ── Agent Tasks ── */}
495→              <div className="mb-6 border border-border-2 rounded-lg overflow-hidden">
496→                <div className="flex items-center gap-2 text-sm font-semibold px-4 py-3 border-b border-border-2 bg-bg-2">
497→                  <AiFill size={16} className="text-(--agent-fg)" /> Agent Tasks
498→                  <Badge variant="outline-primary" size="sm">
499→                    Skill
500→                  </Badge>
501→                  <span className="font-normal text-xs text-fg-3 ml-auto">
502→                    Required skills from ClawHub
503→                  </span>
504→                </div>
505→                <div className="p-4">
506→                  <div className="bg-bg-2 border border-border-2 rounded px-3 py-2.5 text-sm text-fg-2 leading-relaxed mb-4">
507→                    Agents must have{" "}
508→                    <code className="font-mono text-xs bg-bg-3 px-1">
509→                      clawquest
510→                    </code>{" "}
511→                    installed + each required skill below. CQ checks
512→                    capabilities before submission.
513→                  </div>
514→
515→                  <div className="text-sm font-semibold text-fg-1 mt-3 mb-2">
516→                    Required Skills
517→                  </div>
518→                  {requiredSkills.length === 0 ? (
519→                    <div className="text-sm text-fg-3 py-1 pb-2">
520→                      No skills required yet. Search below to add.
521→                    </div>
522→                  ) : (
523→                    <div className="mt-2">
524→                      {requiredSkills.map((skill) => {
525→                        const isCustom = skill.id.startsWith("http");
526→                        return (
527→                          <div
528→                            key={skill.id}
529→                            className="flex items-start gap-4 px-3 py-2 border border-border-2 rounded mb-2 last:mb-0 bg-bg-2/50"
530→                          >
531→                            <div className="flex-1 min-w-0">
532→                              <span className="font-semibold text-sm text-fg-1 truncate block">
533→                                {isCustom
534→                                  ? skill.name
535→                                  : `${skill.id}@${skill.version ?? "latest"}`}
536→                              </span>
537→                              <span className="text-xs text-fg-3 truncate block mt-0.5">
538→                                {skill.desc}
539→                              </span>
540→                              <div className="mt-1">
541→                                {isCustom ? (
542→                                  <Badge variant="outline-muted" size="sm">
543→                                    custom
544→                                  </Badge>
545→                                ) : (
546→                                  <Badge variant="outline-primary" size="sm">
547→                                    {skill.agents} agents
548→                                  </Badge>
549→                                )}
550→                              </div>
551→                            </div>
552→                            <Button
553→                              variant="outline"
554→                              size="sm"
555→                              iconOnly
556→                              onClick={() => onRemoveSkill(skill.id)}
557→                            >
558→                              <Delete2Line size={14} />
559→                            </Button>
560→                          </div>
561→                        );
562→                      })}
563→                    </div>
564→                  )}
565→
566→                  {/* Require verified toggle */}
567→                  {requiredSkills.length > 0 && (
568→                    <label className="flex items-center gap-2 my-4 cursor-pointer select-none">
569→                      <input
570→                        type="checkbox"
571→                        checked={requireVerified}
572→                        onChange={(e) => onSetRequireVerified(e.target.checked)}
573→                        className="accent-accent size-3.5"
574→                      />
575→                      <span className="text-xs text-fg-1 font-medium">
576→                        Require verified skills
577→                      </span>
578→                      <span className="text-xs text-fg-3">
579→                        — only agents who ran Skill Scan can join
580→                      </span>
581→                    </label>
582→                  )}
583→
584→                  <div className="mb-3">
585→                    <div className="relative">
586→                      <SearchLine
587→                        size={16}
588→                        className="absolute left-3 top-1/2 -translate-y-1/2 text-fg-3 pointer-events-none z-10"
589→                      />
590→                      <Input
591→                        className="pl-9"
592→                        type="text"
593→                        placeholder="Search on ClawHub or paste skill URL…"
594→                        value={skillSearch}
595→                        onChange={(e) => {
596→                          const val = e.target.value;
597→                          onSetSkillSearch(val);
598→                          onSetShowSkillResults(true);
599→                          onSetUrlFetchError(null);
600→                          onSetUrlPreview(null);
601→                          if (isSkillUrl(val.trim())) {
602→                            onSetUrlFetching(true);
603→                            fetchSkillFromUrl(val.trim())
604→                              .then((skill) => {
605→                                onSetUrlPreview(skill);
606→                                if (!skill)
607→                                  onSetUrlFetchError(
608→                                    "Could not parse skill.md from this URL",
609→                                  );
610→                              })
611→                              .catch(() =>
612→                                onSetUrlFetchError("Failed to fetch URL"),
613→                              )
614→                              .finally(() => onSetUrlFetching(false));
615→                          }
616→                        }}
617→                        onFocus={() => onSetShowSkillResults(true)}
618→                      />
619→                    </div>
620→
621→                    {/* URL-based skill preview */}
622→                    {showSkillResults &&
623→                      isSkillUrl(skillSearch.trim()) &&
624→                      (urlFetching || urlPreview || urlFetchError) && (
625→                        <div className="border border-border-2 rounded bg-bg-base overflow-hidden overflow-y-auto mb-3 max-h-[360px]">
626→                          <div className="px-3 py-1.5 text-xs text-fg-3 bg-bg-3/50 border-b border-border-2 flex justify-between">
627→                            <span>
628→                              {urlFetching
629→                                ? "Fetching skill.md…"
630→                                : urlPreview
