 59→function useCountdown(expiresAt: string | null) {
 60→  const [timeLeft, setTimeLeft] = useState({
 61→    d: 0,
 62→    h: 0,
 63→    m: 0,
 64→    s: 0,
 65→    ended: false,
 66→  });
 67→
 68→  useEffect(() => {
 69→    if (!expiresAt) return;
 70→    function tick() {
 71→      const diff = new Date(expiresAt!).getTime() - Date.now();
 72→      if (diff <= 0) {
 73→        setTimeLeft({ d: 0, h: 0, m: 0, s: 0, ended: true });
 74→        return;
 75→      }
 76→      const s = Math.floor(diff / 1000);
 77→      const m = Math.floor(s / 60);
 78→      const h = Math.floor(m / 60);
 79→      const d = Math.floor(h / 24);
 80→      setTimeLeft({ d, h: h % 24, m: m % 60, s: s % 60, ended: false });
 81→    }
 82→    tick();
 83→    const id = setInterval(tick, 1000);
 84→    return () => clearInterval(id);
 85→  }, [expiresAt]);
 86→
 87→  return timeLeft;
 88→}
