146→/** Get the external URL for a task based on its actionType and params */
147→function getTaskActionUrl(task: any): string | undefined {
148→  const p = task.params || {};
149→  switch (task.actionType) {
150→    case "follow_account":
151→      return `https://x.com/${p.username}`;
152→    case "like_post":
153→    case "repost":
154→      return p.postUrl;
155→    case "quote_post":
156→      return p.postUrl; // open original tweet so user can quote-tweet it
157→    case "post": {
158→      const content = p.content ? `?text=${encodeURIComponent(p.content)}` : "";
159→      return `https://x.com/intent/tweet${content}`;
160→    }
161→    case "join_server":
162→      return p.inviteUrl;
163→    case "join_channel": {
164→      const ch = p.channelUrl || "";
165→      return ch.startsWith("http")
166→        ? ch
167→        : `https://t.me/${ch.replace(/^@/, "")}`;
168→    }
169→    case "verify_role":
170→      return p.inviteUrl;
171→    default:
172→      return undefined;
173→  }
174→}
