376→function ChipInput({
377→  chips,
378→  onAdd,
379→  onRemove,
380→  placeholder,
381→  validate,
382→  formatChip,
383→  maxChips,
384→  error: externalError,
385→  chipStatus,
386→}: {
387→  chips: string[];
388→  onAdd: (value: string) => void;
389→  onRemove: (index: number) => void;
390→  placeholder: string;
391→  validate?: (value: string) => string | null;
392→  formatChip?: (value: string) => string;
393→  maxChips?: number;
394→  error?: string;
395→  chipStatus?: (value: string) => ChipStatus | undefined;
396→}) {
397→  const [input, setInput] = useState("");
398→  const [error, setError] = useState<string | null>(null);
399→  const atMax = maxChips !== undefined && chips.length >= maxChips;
400→
401→  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
402→    if (e.key === "Enter") {
403→      e.preventDefault();
404→      const trimmed = input.trim();
405→      if (!trimmed) return;
406→      if (atMax) return;
407→      if (validate) {
408→        const err = validate(trimmed);
409→        if (err) {
410→          setError(err);
411→          return;
412→        }
413→      }
414→      const norm = trimmed.replace(/^@/, "").toLowerCase();
415→      if (chips.some((c) => c.replace(/^@/, "").toLowerCase() === norm)) {
416→        setError("Already added");
417→        return;
418→      }
419→      onAdd(trimmed);
420→      setInput("");
421→      setError(null);
422→    } else if (e.key === "Backspace" && input === "" && chips.length > 0) {
423→      onRemove(chips.length - 1);
424→    }
425→  };
426→
427→  const displayError = error || externalError;
428→
429→  return (
430→    <div>
431→      {chips.length > 0 && (
432→        <div className="flex flex-wrap gap-1.5 mb-1.5">
433→          {chips.map((chip, i) => {
434→            const status = chipStatus?.(chip);
435→            return (
436→              <span
437→                key={i}
438→                className={cn(
439→                  "inline-flex items-center gap-1 px-2 py-0.5 rounded-md text-xs border leading-tight",
440→                  status === "pending"
441→                    ? "bg-bg-3 border-border-2 text-fg-3"
442→                    : status === "invalid"
443→                      ? "bg-error-light border-warning text-warning"
444→                      : "border-primary/40 bg-primary/10 text-primary",
445→                )}
446→              >
447→                {status === "pending" && (
448→                  <span className="inline-block size-2.5 border-[1.5px] border-border-2 border-t-fg-3 rounded-full animate-spin" />
449→                )}
450→                {status === "invalid" && (
451→                  <span className="text-xs font-semibold">⚠</span>
452→                )}
453→                <span className="font-mono text-xs">
454→                  {formatChip ? formatChip(chip) : chip}
455→                </span>
456→                <button
457→                  className="bg-transparent border-none text-fg-3 text-base cursor-pointer px-px leading-none ml-0.5 hover:text-destructive"
458→                  onClick={() => onRemove(i)}
459→                >
460→                  ×
461→                </button>
462→              </span>
463→            );
464→          })}
465→        </div>
466→      )}
467→      {!atMax && (
468→        <input
469→          className={cn(
470→            "flex h-9 w-full rounded border border-border-2 bg-transparent px-3 py-1 text-sm shadow-sm transition-colors placeholder:text-fg-3 focus-visible:outline-hidden focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 chip-input",
471→            displayError && "border-destructive focus-visible:ring-destructive",
472→          )}
473→          type="text"
474→          placeholder={chips.length > 0 ? "Add another… ↵" : placeholder}
475→          value={input}
476→          onChange={(e) => {
477→            setInput(e.target.value);
478→            setError(null);
479→          }}
480→          onKeyDown={handleKeyDown}
481→        />
482→      )}
483→      {!atMax && !displayError && input.length === 0 && chips.length === 0 && (
484→        <div className="text-xs text-fg-3 leading-snug mt-2">
485→          Press ↵ Enter to confirm
486→        </div>
487→      )}
488→      {displayError && (
489→        <div className="text-xs text-destructive mt-2 leading-snug">
490→          {displayError}
491→        </div>
492→      )}
493→    </div>
494→  );
495→}
