289→              guildId: (entry.params.guildId ?? "").trim(),
290→              roleId: (entry.params.roleId ?? "").trim(),
291→              roleName: (
292→                entry.params.roleName ??
293→                entry.params.role ??
294→                ""
295→              ).trim(),
296→            },
297→            requireTagFriends: false,
298→          });
299→        break;
300→      case "join_channel":
301→        if (entry.chips.length > 0)
302→          tasks.push({
303→            id: crypto.randomUUID(),
304→            platform,
305→            actionType: "join_channel",
