316→// ─── Reverse-map API QuestTask[] → SocialEntry[] for edit mode ──────────────
317→function questTasksToSocialEntries(tasks: any[]): SocialEntry[] {
318→  const groups = new Map<string, SocialEntry>();
319→  for (const task of tasks) {
320→    const key = `${task.platform}-${task.actionType}`;
321→    const platformName =
322→      task.platform === "x"
323→        ? "X"
324→        : task.platform === "discord"
325→          ? "Discord"
326→          : "Telegram";
327→    const actionDef = PLATFORM_ACTIONS[platformName]?.find(
328→      (a) => a.type === task.actionType,
329→    );
330→    if (!groups.has(key)) {
331→      groups.set(key, {
332→        platform: platformName,
333→        action: actionDef?.label ?? task.label,
334→        actionType: task.actionType,
335→        icon: platformName,
336→        params: {},
337→        chips: [],
338→        requireTagFriends: task.requireTagFriends ?? false,
339→      });
340→    }
341→    const entry = groups.get(key)!;
342→    switch (task.actionType) {
343→      case "follow_account":
344→        entry.chips.push(task.params?.username ?? "");
345→        break;
346→      case "like_post":
347→      case "repost":
348→        entry.chips.push(task.params?.postUrl ?? "");
349→        break;
350→      case "post":
351→        entry.params.content = task.params?.content ?? "";
352→        break;
353→      case "quote_post":
354→        entry.chips.push(task.params?.postUrl ?? "");
355→        entry.params.content = task.params?.content ?? "";
356→        break;
357→      case "join_server":
358→        entry.chips.push(task.params?.inviteUrl ?? "");
359→        break;
360→      case "verify_role":
361→        entry.chips.push(task.params?.inviteUrl ?? "");
362→        entry.params.guildId = task.params?.guildId ?? "";
363→        entry.params.roleId = task.params?.roleId ?? "";
364→        entry.params.roleName = task.params?.roleName ?? "";
365→        entry.params.role = task.params?.roleName ?? "";
366→        break;
367→      case "join_channel":
368→        entry.chips.push(task.params?.channelUrl ?? "");
369→        break;
370→    }
371→  }
372→  return Array.from(groups.values());
373→}
