function ChipInput({
  chips,
  onAdd,
  onRemove,
  placeholder,
  validate,
  formatChip,
  maxChips,
  error: externalError,
  chipStatus,
}: {
  chips: string[];
  onAdd: (value: string) => void;
  onRemove: (index: number) => void;
  placeholder: string;
  validate?: (value: string) => string | null;
  formatChip?: (value: string) => string;
  maxChips?: number;
  error?: string;
  chipStatus?: (value: string) => ChipStatus | undefined;
}) {
  const [input, setInput] = useState("");
  const [error, setError] = useState<string | null>(null);
  const atMax = maxChips !== undefined && chips.length >= maxChips;

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      e.preventDefault();
      const trimmed = input.trim();
      if (!trimmed) return;
      if (atMax) return;
      if (validate) {
        const err = validate(trimmed);
        if (err) {
          setError(err);
          return;
        }
      }
      const norm = trimmed.replace(/^@/, "").toLowerCase();
      if (chips.some((c) => c.replace(/^@/, "").toLowerCase() === norm)) {
        setError("Already added");
        return;
      }
      onAdd(trimmed);
      setInput("");
      setError(null);
    } else if (e.key === "Backspace" && input === "" && chips.length > 0) {
      onRemove(chips.length - 1);
    }
  };

  const displayError = error || externalError;

  return (
    <div>
      {chips.length > 0 && (
        <div className="flex flex-wrap gap-1.5 mb-1.5">
          {chips.map((chip, i) => {
            const status = chipStatus?.(chip);
            return (
              <span
                key={i}
                className={cn(
                  "inline-flex items-center gap-1 px-2 py-0.5 rounded-md text-xs border leading-tight",
                  status === "pending"
                    ? "bg-bg-3 border-border-2 text-fg-3"
                    : status === "invalid"
                      ? "bg-error-light border-warning text-warning"
                      : "border-primary/40 bg-primary/10 text-primary",
                )}
              >
                {status === "pending" && (
                  <span className="inline-block size-2.5 border-[1.5px] border-border-2 border-t-fg-3 rounded-full animate-spin" />
                )}
                {status === "invalid" && (
                  <span className="text-xs font-semibold">⚠</span>
                )}
                <span className="font-mono text-xs">
                  {formatChip ? formatChip(chip) : chip}
                </span>
                <button
                  className="bg-transparent border-none text-fg-3 text-base cursor-pointer px-px leading-none ml-0.5 hover:text-destructive"
                  onClick={() => onRemove(i)}
                >
                  ×
                </button>
              </span>
            );
          })}
        </div>
      )}
      {!atMax && (
        <input
          className={cn(
            "flex h-9 w-full rounded border border-border-2 bg-transparent px-3 py-1 text-sm shadow-sm transition-colors placeholder:text-fg-3 focus-visible:outline-hidden focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 chip-input",
            displayError && "border-destructive focus-visible:ring-destructive",
          )}
          type="text"
          placeholder={chips.length > 0 ? "Add another… ↵" : placeholder}
          value={input}
          onChange={(e) => {
            setInput(e.target.value);
            setError(null);
          }}
          onKeyDown={handleKeyDown}
        />
      )}
      {!atMax && !displayError && input.length === 0 && chips.length === 0 && (
        <div className="text-xs text-fg-3 leading-snug mt-2">
          Press ↵ Enter to confirm
        </div>
      )}
      {displayError && (
        <div className="text-xs text-destructive mt-2 leading-snug">
          {displayError}
        </div>
      )}
    </div>
  );
}

// ─── Discord role fields (dynamic fetch) ─────────────────────────────────────

interface DiscordRoleOption {
  id: string;
  name: string;
  color: number;
  position: number;
}

