    removeChip: (i: number, chipIdx: number) => void;
    errors?: TaskValidationError[];
    chipStatus?: (value: string) => ChipStatus | undefined;
  }>;
  isSkillUrl: (url: string) => boolean;
  fetchSkillFromUrl: (url: string) => Promise<ClawHubSkill | null>;
}

