  skillSearchLoading,
  showSkillResults,
  urlFetching,
  urlPreview,
  urlFetchError,
  taskErrors,
  addedSkillIds,
  onToggle,
  onSetActivePlatform,
  onAddHumanTask,
  onRemoveHumanTask,
  onSetExpandedTask,
