                                      task.chips.length === 0 &&
                                      !task.params["content"]
                                    ) {
                                      onRemoveHumanTask(i);
                                    }
                                    onSetExpandedTask(null);
                                  }}
                                >
                                  Cancel
                                </Button>
                                <Button
                                  size="lg"
                                  onClick={() => onSetExpandedTask(null)}
                                >
                                  {task.chips.length > 0 ||
                                  task.params["content"]
