const API_BASE = import.meta.env.VITE_API_URL ?? "http://localhost:3000";
const ESCROW_NETWORK_MODE =
  import.meta.env.VITE_ESCROW_NETWORK_MODE ?? "testnet";
const IS_TESTNET = ESCROW_NETWORK_MODE === "testnet";

// ─── Types ────────────────────────────────────────────────────────────────────

type Tab = "details" | "reward" | "tasks" | "preview";
type QuestType = "FCFS" | "LEADERBOARD" | "LUCKY_DRAW";
type PaymentRail = "crypto" | "fiat" | "llm";

interface SocialEntry {
  platform: string;
  action: string;
  actionType: string;
  icon: string;
  params: Record<string, string>;
  chips: string[];
  requireTagFriends?: boolean;
}

interface FormData {
  title: string;
  description: string;
  startAt: string;
  endAt: string;
  rail: PaymentRail;
  network: string;
  token: string;
  type: QuestType;
  // Shared across all distribution types
  total: string;
  winners: string;
  // Lucky Draw only
  drawTime: string;
  // Funding method (auto-set based on rail)
  fundingMethod?: "crypto" | "stripe";
}

// ─── Default network (testnet vs mainnet) ─────────────────────────────────────
const DEFAULT_NETWORK = IS_TESTNET ? "Base Sepolia" : "Base";

// ─── Platform / action data ────────────────────────────────────────────────────

type ActionDef = {
  type: string;
  label: string;
  fields:
    | "follow"
    | "post_url"
    | "post_content"
    | "quote_post"
    | "discord_join"
    | "discord_role"
    | "telegram_join";
};

const PLATFORM_ACTIONS: Record<string, ActionDef[]> = {
  X: [
    { type: "follow_account", label: "Follow on X", fields: "follow" },
    { type: "like_post", label: "Like a Post", fields: "post_url" },
    { type: "repost", label: "Repost a Post", fields: "post_url" },
    { type: "post", label: "Post on X", fields: "post_content" },
    { type: "quote_post", label: "Quote a Post", fields: "quote_post" },
  ],
  Discord: [
    {
      type: "join_server",
      label: "Join a Discord Server",
      fields: "discord_join",
    },
    {
      type: "verify_role",
      label: "Verify Role in Discord",
      fields: "discord_role",
    },
  ],
  Telegram: [
    {
      type: "join_channel",
      label: "Join a Group or Channel",
      fields: "telegram_join",
    },
  ],
};

// ─── Task validation (matches API-side regex) ─────────────────────────────────

const X_POST_URL_RE = /^https?:\/\/(x\.com|twitter\.com)\/\w+\/status\/\d+/i;
const X_USERNAME_RE = /^@?[\w]{1,15}$/;
const DISCORD_INVITE_RE =
  /^https?:\/\/(discord\.gg|discord\.com\/invite)\/[\w-]+$/i;
const TELEGRAM_CHANNEL_RE = /^(@[\w]{5,32}|https?:\/\/t\.me\/[\w]+)$/i;

interface TaskValidationError {
  index: number;
  field: string;
  message: string;
}

function validateSocialTasks(tasks: SocialEntry[]): TaskValidationError[] {
  const errors: TaskValidationError[] = [];
  tasks.forEach((task, i) => {
    switch (task.actionType) {
      case "follow_account":
        if (task.chips.length === 0)
          errors.push({
            index: i,
            field: "chips",
            message: "Add at least one X username (type & press ↵)",
          });
        break;
      case "like_post":
      case "repost":
        if (task.chips.length === 0)
          errors.push({
            index: i,
            field: "chips",
            message: "Add at least one post URL (type & press ↵)",
          });
        break;
      case "post":
        if (!task.params.content?.trim())
          errors.push({
            index: i,
            field: "content",
            message: "Post content is required",
          });
        else if (task.params.content.length > 280)
          errors.push({
            index: i,
            field: "content",
            message: "Post content exceeds 280 characters",
          });
        break;
      case "quote_post":
        if (task.chips.length === 0)
          errors.push({
            index: i,
            field: "chips",
            message: "Add the post URL to quote (type & press ↵)",
          });
        break;
      case "join_server":
        if (task.chips.length === 0)
          errors.push({
            index: i,
            field: "chips",
            message: "Add a Discord invite URL (type & press ↵)",
          });
        break;
      case "verify_role":
        if (task.chips.length === 0)
          errors.push({
            index: i,
            field: "chips",
            message: "Add a Discord invite URL (type & press ↵)",
          });
        if (!task.params.roleId?.trim() && !task.params.role?.trim())
          errors.push({
            index: i,
            field: "role",
            message: "Select a role to verify",
          });
        break;
      case "join_channel":
        if (task.chips.length === 0)
          errors.push({
            index: i,
            field: "chips",
            message: "Add a Telegram channel (type & press ↵)",
          });
        break;
    }
  });
  return errors;
}

/** Transform frontend SocialEntry[] → API QuestTask[] (chips expand to multiple tasks) */
function socialEntriesToTasks(entries: SocialEntry[]): any[] {
  const tasks: any[] = [];
  for (const entry of entries) {
    const platform = entry.platform.toLowerCase() as
      | "x"
      | "discord"
      | "telegram";
    switch (entry.actionType) {
      case "follow_account":
        for (const chip of entry.chips) {
          tasks.push({
            id: crypto.randomUUID(),
            platform,
            actionType: "follow_account",
            label: `Follow @${chip.replace(/^@/, "")}`,
            params: { username: chip.replace(/^@/, "").trim() },
            requireTagFriends: false,
          });
        }
        break;
      case "like_post":
      case "repost":
        for (const chip of entry.chips) {
          tasks.push({
            id: crypto.randomUUID(),
            platform,
            actionType: entry.actionType,
            label: `${entry.actionType === "like_post" ? "Like" : "Repost"} post`,
            params: { postUrl: chip.trim() },
            requireTagFriends: false,
          });
        }
        break;
      case "post":
        tasks.push({
          id: crypto.randomUUID(),
          platform,
          actionType: "post",
          label: entry.action,
          params: { content: (entry.params.content ?? "").trim() },
          requireTagFriends: entry.requireTagFriends ?? false,
        });
        break;
      case "quote_post":
        if (entry.chips.length > 0)
          tasks.push({
            id: crypto.randomUUID(),
            platform,
            actionType: "quote_post",
            label: entry.action,
            params: {
              postUrl: entry.chips[0].trim(),
              ...(entry.params.content
                ? { content: entry.params.content.trim() }
                : {}),
            },
            requireTagFriends: entry.requireTagFriends ?? false,
          });
        break;
      case "join_server":
        if (entry.chips.length > 0)
          tasks.push({
            id: crypto.randomUUID(),
            platform,
            actionType: "join_server",
            label: entry.action,
            params: { inviteUrl: entry.chips[0].trim() },
            requireTagFriends: false,
          });
        break;
      case "verify_role":
        if (entry.chips.length > 0)
          tasks.push({
            id: crypto.randomUUID(),
            platform,
            actionType: "verify_role",
            label: entry.action,
            params: {
              inviteUrl: entry.chips[0].trim(),
              guildId: (entry.params.guildId ?? "").trim(),
              roleId: (entry.params.roleId ?? "").trim(),
              roleName: (
                entry.params.roleName ??
                entry.params.role ??
                ""
              ).trim(),
            },
            requireTagFriends: false,
          });
        break;
      case "join_channel":
        if (entry.chips.length > 0)
          tasks.push({
            id: crypto.randomUUID(),
            platform,
            actionType: "join_channel",
            label: entry.action,
            params: { channelUrl: entry.chips[0].trim() },
            requireTagFriends: false,
          });
        break;
    }
  }
  return tasks;
}

// ─── Reverse-map API QuestTask[] → SocialEntry[] for edit mode ──────────────
function questTasksToSocialEntries(tasks: any[]): SocialEntry[] {
  const groups = new Map<string, SocialEntry>();
  for (const task of tasks) {
    const key = `${task.platform}-${task.actionType}`;
    const platformName =
      task.platform === "x"
        ? "X"
        : task.platform === "discord"
          ? "Discord"
          : "Telegram";
    const actionDef = PLATFORM_ACTIONS[platformName]?.find(
      (a) => a.type === task.actionType,
    );
    if (!groups.has(key)) {
      groups.set(key, {
        platform: platformName,
        action: actionDef?.label ?? task.label,
        actionType: task.actionType,
        icon: platformName,
        params: {},
        chips: [],
        requireTagFriends: task.requireTagFriends ?? false,
      });
    }
    const entry = groups.get(key)!;
    switch (task.actionType) {
      case "follow_account":
        entry.chips.push(task.params?.username ?? "");
        break;
      case "like_post":
      case "repost":
        entry.chips.push(task.params?.postUrl ?? "");
        break;
      case "post":
        entry.params.content = task.params?.content ?? "";
        break;
      case "quote_post":
        entry.chips.push(task.params?.postUrl ?? "");
        entry.params.content = task.params?.content ?? "";
        break;
      case "join_server":
        entry.chips.push(task.params?.inviteUrl ?? "");
        break;
      case "verify_role":
        entry.chips.push(task.params?.inviteUrl ?? "");
        entry.params.guildId = task.params?.guildId ?? "";
        entry.params.roleId = task.params?.roleId ?? "";
        entry.params.roleName = task.params?.roleName ?? "";
        entry.params.role = task.params?.roleName ?? "";
        break;
      case "join_channel":
        entry.chips.push(task.params?.channelUrl ?? "");
        break;
    }
  }
  return Array.from(groups.values());
}

// ─── Chip Input (Enter-to-confirm, multi-value) ─────────────────────────────
function ChipInput({
  chips,
  onAdd,
  onRemove,
  placeholder,
  validate,
  formatChip,
  maxChips,
  error: externalError,
  chipStatus,
}: {
  chips: string[];
  onAdd: (value: string) => void;
  onRemove: (index: number) => void;
  placeholder: string;
  validate?: (value: string) => string | null;
  formatChip?: (value: string) => string;
  maxChips?: number;
  error?: string;
  chipStatus?: (value: string) => ChipStatus | undefined;
}) {
  const [input, setInput] = useState("");
  const [error, setError] = useState<string | null>(null);
  const atMax = maxChips !== undefined && chips.length >= maxChips;

  const commitValue = () => {
    const trimmed = input.trim();
    if (!trimmed) return;
    if (atMax) return;
    if (validate) {
      const err = validate(trimmed);
      if (err) {
        setError(err);
        return;
      }
    }
    const norm = trimmed.replace(/^@/, "").toLowerCase();
    if (chips.some((c) => c.replace(/^@/, "").toLowerCase() === norm)) {
      setError("Already added");
      return;
    }
    onAdd(trimmed);
    setInput("");
    setError(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      e.preventDefault();
      commitValue();
    } else if (e.key === "Backspace" && input === "" && chips.length > 0) {
      onRemove(chips.length - 1);
    }
  };

  const displayError = error || externalError;

  return (
    <div>
      {chips.length > 0 && (
        <div className="flex flex-wrap gap-1.5 mb-1.5">
          {chips.map((chip, i) => {
            const status = chipStatus?.(chip);
            return (
              <span
                key={i}
                className={cn(
                  "inline-flex items-center gap-1 px-2 py-0.5 rounded-md text-xs border leading-tight",
                  status === "pending"
                    ? "bg-bg-3 border-border-2 text-fg-3"
                    : status === "invalid"
                      ? "bg-error-light border-warning text-warning"
                      : "border-primary/40 bg-primary/10 text-primary",
                )}
              >
                {status === "pending" && (
                  <span className="inline-block size-2.5 border-[1.5px] border-border-2 border-t-fg-3 rounded-full animate-spin" />
                )}
                {status === "invalid" && (
                  <span className="text-xs font-semibold">⚠</span>
                )}
                <span className="font-mono text-xs">
                  {formatChip ? formatChip(chip) : chip}
                </span>
                <button
                  className="bg-transparent border-none text-fg-3 text-base cursor-pointer px-px leading-none ml-0.5 hover:text-destructive"
                  onClick={() => onRemove(i)}
                >
                  ×
                </button>
              </span>
            );
          })}
        </div>
      )}
      {!atMax && (
        <input
          className={cn(
            "flex h-9 w-full rounded border border-border-2 bg-transparent px-3 py-1 text-sm shadow-sm transition-colors placeholder:text-fg-3 focus-visible:outline-hidden focus-visible:ring-1 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 chip-input",
            displayError && "border-destructive focus-visible:ring-destructive",
          )}
          type="text"
          placeholder={chips.length > 0 ? "Add another… ↵" : placeholder}
          value={input}
          onChange={(e) => {
            setInput(e.target.value);
            setError(null);
          }}
          onKeyDown={handleKeyDown}
        />
      )}
      {!atMax && !displayError && input.length === 0 && chips.length === 0 && (
        <div className="text-xs text-fg-3 leading-snug mt-2">
          Press ↵ Enter to confirm
        </div>
      )}
      {displayError && (
        <div className="text-xs text-destructive mt-2 leading-snug">
          {displayError}
        </div>
      )}
    </div>
  );
}

// ─── Discord role fields (dynamic fetch) ─────────────────────────────────────

interface DiscordRoleOption {
  id: string;
  name: string;
  color: number;
  position: number;
}

function DiscordRoleFields({
  task,
  idx,
  setTaskParam,
  addChip,
  removeChip,
  chipError,
  chipStatus,
  fieldError,
}: {
  task: SocialEntry;
  idx: number;
  setTaskParam: (i: number, key: string, val: string) => void;
  addChip: (i: number, value: string) => void;
  removeChip: (i: number, chipIdx: number) => void;
  chipError?: string;
  chipStatus?: (value: string) => ChipStatus | undefined;
  fieldError: (field: string) => string | undefined;
}) {
  const { session } = useAuth();
  const [guildId, setGuildId] = useState(task.params.guildId ?? "");
  const [guildName, setGuildName] = useState("");
  const [botPresent, setBotPresent] = useState<boolean | null>(null);
  const [roles, setRoles] = useState<DiscordRoleOption[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [refreshCount, setRefreshCount] = useState(0);

  // Extract invite code from URL
  const extractInviteCode = (url: string): string | null => {
    const m = url.match(/discord\.(?:gg|com\/invite)\/([A-Za-z0-9-]+)/);
    return m ? m[1] : null;
  };

  // Fetch guild info when chip changes
  const currentChip = task.chips[0] ?? "";
  useEffect(() => {
    if (!currentChip) {
      setGuildId("");
      setGuildName("");
      setBotPresent(null);
      setRoles([]);
      setError("");
      return;
    }
    const code = extractInviteCode(currentChip);
    if (!code) return;

    let cancelled = false;
    setLoading(true);
    setError("");

    fetch(
      `${API_BASE}/discord/guild-info?inviteCode=${encodeURIComponent(code)}`,
    )
      .then((r) => r.json())
      .then((json) => {
        if (cancelled) return;
        if (json.error) {
          setError(json.error.message);
          setBotPresent(null);
          setLoading(false);
          return;
        }
        const d = json.data as {
          guildId: string;
          guildName: string;
          botPresent: boolean;
        };
        setGuildId(d.guildId);
        setGuildName(d.guildName);
        setBotPresent(d.botPresent);
        setTaskParam(idx, "guildId", d.guildId);

        if (d.botPresent && session?.access_token) {
          fetch(
            `${API_BASE}/discord/guild-roles?guildId=${encodeURIComponent(d.guildId)}`,
            {
              headers: { Authorization: `Bearer ${session.access_token}` },
            },
          )
            .then((r2) => r2.json())
            .then((j2) => {
              if (cancelled) return;
              if (j2.data?.roles) setRoles(j2.data.roles);
              setLoading(false);
            })
            .catch(() => {
              if (!cancelled) setLoading(false);
            });
        } else {
          setLoading(false);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setError("Failed to check server");
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [currentChip, refreshCount]); // eslint-disable-line react-hooks/exhaustive-deps

  // Open bot invite URL
  const handleInviteBot = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const gid = guildId || "";
    try {
      const res = await fetch(
        `${API_BASE}/discord/bot-invite-url?guildId=${encodeURIComponent(gid)}`,
      );
      const json = await res.json();
      if (json.data?.url) window.open(json.data.url, "_blank");
    } catch {
      /* ignore */
    }
  };

  // Re-check bot presence after inviting
  const handleRefresh = () => {
    if (!currentChip) return;
    setRefreshCount((c) => c + 1);
  };

  // Handle role selection — store both roleId and roleName
  const handleRoleSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const roleId = e.target.value;
    const role = roles.find((r) => r.id === roleId);
    setTaskParam(idx, "roleId", roleId);
    setTaskParam(idx, "roleName", role?.name ?? "");
    setTaskParam(idx, "role", role?.name ?? ""); // backward compat for display
  };

  return (
    <>
      <div className="flex items-center gap-2 px-4 py-3 bg-bg-2 border border-border-2 rounded text-xs text-fg-2 mb-4">
        <span className="flex-1">
          {botPresent === true && guildName ? (
            <>
              Bot is in <strong>{guildName}</strong> — roles loaded.
            </>
          ) : (
            <>
              Add the <strong>ClawQuest bot</strong> to your server to enable
              role verification.
            </>
          )}
        </span>
        {botPresent !== true && (
          <Button variant="default-tonal" size="sm" onClick={handleInviteBot}>
            Invite Bot
          </Button>
        )}
        {botPresent === false && (
          <Button
            variant="ghost"
            size="sm"
            className="ml-1"
            onClick={handleRefresh}
          >
            Refresh
          </Button>
        )}
      </div>
      <div className="space-y-2 mb-4">
        <Label>Discord Server URL</Label>
        <div className="text-xs text-fg-3 leading-snug">
          Invite link. Press ↵ to confirm.
        </div>
        <ChipInput
          chips={task.chips}
          onAdd={(val) => addChip(idx, val)}
          onRemove={(ci) => removeChip(idx, ci)}
          placeholder="https://discord.gg/..."
          validate={(v) =>
            DISCORD_INVITE_RE.test(v.trim())
              ? null
              : "Must be a valid Discord invite link"
          }
          maxChips={1}
          error={chipError}
          chipStatus={chipStatus}
        />
        {loading && (
          <div className="text-xs text-accent leading-snug">
            Checking server...
          </div>
        )}
        {error && (
          <div className="text-xs text-destructive mt-0.5 leading-snug">
            {error}
          </div>
        )}
      </div>
      <div className="space-y-2">
        <Label>Required Role</Label>
        <div className="text-xs text-fg-3 leading-snug">
          {botPresent === true
            ? "Select a role from the server."
            : "Invite the bot first to load roles."}
        </div>
        <select
          className={cn(
            "flex h-9 w-full rounded border border-border-2 bg-transparent px-3 py-1 text-sm shadow-sm focus-visible:outline-hidden focus-visible:ring-1 focus-visible:ring-ring",
            fieldError("role") &&
              "border-destructive focus-visible:ring-destructive",
          )}
          value={task.params.roleId ?? ""}
          onChange={handleRoleSelect}
          disabled={roles.length === 0}
        >
          <option value="" disabled>
            {loading
              ? "Loading roles..."
              : roles.length === 0
                ? "— No roles available —"
                : "— Select a role —"}
          </option>
          {roles.map((r) => (
            <option key={r.id} value={r.id}>
              {r.name}
            </option>
          ))}
        </select>
        {fieldError("role") && (
          <div className="text-xs text-destructive mt-0.5 leading-snug">
            {fieldError("role")}
          </div>
        )}
      </div>
    </>
  );
}

